// ─── Lookup Maps ──────────────────────────────────────────────

/** Slug → CityData lookup */
export const CITY_BY_SLUG: Record<string, CityData> = {};
for (const city of CITIES) {
  CITY_BY_SLUG[city.slug] = city;
}

/** State code → CityData[] lookup */
export const CITIES_BY_STATE: Record<string, CityData[]> = {};
for (const city of CITIES) {
  if (!CITIES_BY_STATE[city.stateCode]) CITIES_BY_STATE[city.stateCode] = [];
  CITIES_BY_STATE[city.stateCode].push(city);
}

/** Get a city by slug, returns undefined if not found */
export function getCityBySlug(slug: string): CityData | undefined {
  return CITY_BY_SLUG[slug];
}

/** Get all cities in a state (by state code) */
export function getCitiesByState(stateCode: string): CityData[] {
  return CITIES_BY_STATE[stateCode.toUpperCase()] || [];
}

/** Get all city slugs */
export function getAllCitySlugs(): string[] {
  return CITIES.map(c => c.slug);
}
